import React, { useState } from 'react';
import { bundlesData } from './data/bundles';

function App() {
  const [purchased, setPurchased] = useState([]);

  const handlePayment = (bundleId) => {
    const options = {
      key: "YOUR_RAZORPAY_KEY", // Replace with your Live/Test Key
      amount: 6900, 
      currency: "INR",
      name: "VFX VAULT",
      description: "Instant Access Bundle",
      // Prefill skips the "Enter Email/Phone" screen for the user
      prefill: { contact: "9999999999", email: "pay@vfxvault.com" },
      config: {
        display: {
          blocks: {
            banks: { name: 'UPI & QR Options', instruments: [{ method: 'upi' }] },
          },
          sequence: ['block.banks'],
        },
      },
      handler: function(response) {
        if(response.razorpay_payment_id) setPurchased([...purchased, bundleId]);
      },
      theme: { color: "#00FFC2" }
    };
    new window.Razorpay(options).open();
  };

  return (
    <div className="min-h-screen pt-20 pb-12 px-8">
      <header className="text-center mb-20">
        <h1 className="text-6xl font-black italic tracking-tighter mb-4">VFX VAULT</h1>
        <p className="text-vfx-cyan font-mono text-sm tracking-[0.3em]">4K PREMIUM ASSETS • ₹69 ONLY</p>
      </header>

      <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
        {bundlesData.map((bundle) => (
          <div key={bundle.id} className="perspective-1000 group">
            <div className="vfx-card rounded-[2.5rem] p-5 transform group-hover:rotate-y-12 group-hover:-translate-y-4 shadow-2xl">
              <img 
                src={`/thumbnails/${bundle.thumb}`} 
                className="w-full h-64 object-cover rounded-3xl mb-6 grayscale group-hover:grayscale-0 transition duration-700"
                alt="VFX"
              />
              <h2 className="text-xl font-bold mb-4">{bundle.name}</h2>
              
              <div className="flex justify-between items-center">
                <span className="text-2xl font-black text-vfx-cyan">₹69</span>
                
                {purchased.includes(bundle.id) ? (
                  <a href={`/bundles/${bundle.zip}`} download className="bg-white text-black font-bold py-2 px-6 rounded-xl animate-pulse">DOWNLOAD</a>
                ) : (
                  <button onClick={() => handlePayment(bundle.id)} className="bg-vfx-cyan/10 border border-vfx-cyan text-vfx-cyan font-bold py-2 px-6 rounded-xl hover:bg-vfx-cyan hover:text-black transition-all">BUY NOW</button>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
